+// ─── Drawing engine ────────────────────────────────────────────────
+
+function drawSpriteDef(
+  ctx: CanvasRenderingContext2D,
+  sprite: string[],
+  palette: Record<string, string>,
+  x: number, y: number, s: number,
+  flipH = false,
+) {
+  const w = sprite[0]?.length ?? 16;
+  const ps = Math.ceil(s);
+  for (let row = 0; row < sprite.length; row++) {
+    const line = sprite[row];
+    for (let col = 0; col < line.length; col++) {
+      const ch = line[col];
+      if (ch === ' ' || ch === '0') continue;
+      const color = palette[ch];
+      if (!color) continue;
+      const px = flipH ? x + (w - 1 - col) * s : x + col * s;
+      ctx.fillStyle = color;
+      ctx.fillRect(Math.round(px), Math.round(y + row * s), ps, ps);
+    }
+  }
+}
+
+// ─── Walk cycle sprites ─────────────────────────────────────────────
+
+// We create 4 frames per direction with simple leg movement by shifting leg pixels
+// We'll define a simple leg pattern for each frame and direction
+
+// Base character sprite for walking (simplified example, replace with actual sprite)
+// For demonstration, we assume sprites are 16x16 pixels with characters representing colors
+// We'll simulate leg movement by changing pixels in the leg area
+
+// For each direction, define 4 frames of leg positions (strings arrays)
+// For simplicity, reuse the base sprite and modify leg pixels per frame
+
+// We'll create a helper function to generate walk frames by shifting leg pixels
+
+function generateWalkFrames(baseSprite: string[]): string[][] {
+  // baseSprite is array of strings (rows)
+  // We'll create 4 frames by shifting leg pixels left/right/up/down
+  // Here we simulate leg movement by toggling pixels in leg area (rows 12-15)
+  const frames: string[][] = [];
+  for (let frame = 0; frame < 4; frame++) {
+    const newSprite = baseSprite.map(line => line.split(''));
+    // Simple leg movement pattern:
+    // frame 0 and 2: legs neutral
+    // frame 1: left leg forward, right leg back
+    // frame 3: left leg back, right leg forward
+    // We'll simulate by toggling pixels in leg area columns 5-10, rows 12-15
+    if (frame === 1) {
+      // left leg forward (shift some pixels right)
+      for (let r = 12; r < 16; r++) {
+        if (newSprite[r][6] === 'l') { newSprite[r][6] = ' '; newSprite[r][7] = 'l'; }
+        if (newSprite[r][9] === 'r') { newSprite[r][9] = ' '; newSprite[r][8] = 'r'; }
+      }
+    } else if (frame === 3) {
+      // left leg back (shift some pixels left)
+      for (let r = 12; r < 16; r++) {
+        if (newSprite[r][6] === 'l') { newSprite[r][6] = ' '; newSprite[r][5] = 'l'; }
+        if (newSprite[r][9] === 'r') { newSprite[r][9] = ' '; newSprite[r][10] = 'r'; }
+      }
+    }
+    frames.push(newSprite.map(arr => arr.join('')));
+  }
+  return frames;
+}
+
+// For demonstration, we will create a simple walk cycle for each character type and direction
+// Here we just create dummy frames by reusing the base sprite 4 times (real implementation would be more complex)
+
+// We'll define a new function drawWalkingCharacter as requested
+
+/**
+ * Draw a walking character with 4-frame walk cycle and leg movement
+ * @param ctx CanvasRenderingContext2D
+ * @param x number - x position
+ * @param y number - y position
+ * @param type CharacterType
+ * @param frame number - current animation frame (0 to 3)
+ * @param direction 'up' | 'down' | 'left' | 'right'
+ */
+export function drawWalkingCharacter(
+  ctx: CanvasRenderingContext2D,
+  x: number,
+  y: number,
+  type: CharacterType,
+  frame: number,
+  direction: 'up' | 'down' | 'left' | 'right',
+) {
+  const baseSprite = CHAR_SPRITES[type];
+  if (!baseSprite) return;
+  const palette = PALETTE_MAP[type];
+  if (!palette) return;
+
+  // For simplicity, assume baseSprite is a single frame facing down
+  // We'll create 4 frames for walking down, and flip/rotate for other directions
+  // Here we create 4 frames with leg movement by toggling pixels in leg area
+
+  // We'll create 4 frames once and cache them per type and direction
+  // For now, just create frames on the fly
+
+  // Create 4 frames of walk cycle
+  // For demonstration, just use baseSprite repeated 4 times
+  // In real case, would be different sprites per frame
+  // We'll simulate leg movement by offsetting legs pixels in frame 1 and 3
+
+  // We will create a helper function to modify legs per frame
+
+  // Clone base sprite to array of arrays
+  const frames: string[][] = [];
+  for (let f = 0; f < 4; f++) {
+    const spriteCopy = baseSprite.map(line => line.split(''));
+    // Leg movement simulation:
+    // For down direction, legs are rows 12-15, columns 5-10 (example)
+    // frame 1: left leg forward (shift right), right leg back (shift left)
+    // frame 3: left leg back (shift left), right leg forward (shift right)
+    if (direction === 'down') {
+      if (f === 1) {
+        for (let r = 12; r < Math.min(spriteCopy.length, 16); r++) {
+          if (spriteCopy[r][6] === 'l') { spriteCopy[r][6] = ' '; spriteCopy[r][7] = 'l'; }
+          if (spriteCopy[r][9] === 'r') { spriteCopy[r][9] = ' '; spriteCopy[r][8] = 'r'; }
+        }
+      } else if (f === 3) {
+        for (let r = 12; r < Math.min(spriteCopy.length, 16); r++) {
+          if (spriteCopy[r][6] === 'l') { spriteCopy[r][6] = ' '; spriteCopy[r][5] = 'l'; }
+          if (spriteCopy[r][9] === 'r') { spriteCopy[r][9] = ' '; spriteCopy[r][10] = 'r'; }
+        }
+      }
+    }
+    // For other directions, could add similar leg movement logic or flip horizontally
+    frames.push(spriteCopy.map(arr => arr.join('')));
+  }
+
+  // Determine flipH for left direction
+  const flipH = direction === 'left';
+
+  // Select frame modulo 4
+  const f = frame % 4;
+
+  // Draw the selected frame
+  drawSpriteDef(ctx, frames[f], palette, x, y, 2, flipH);
+}
+
+// ─── Character movement (updated) ────────────────────────────────────────────
+
+interface CharState { x: number; y: number; tx: number; ty: number; dir: string; wf: number; moving: boolean; idle: number }
+const charStates = new Map<string, CharState>();
+
+function getCS(id: string, sx: number, sy: number): CharState {
+  if (!charStates.has(id)) charStates.set(id, { x: sx, y: sy, tx: sx, ty: sy, dir: 'down', wf: 0, moving: false, idle: Math.random() * 200 });
+  return charStates.get(id)!;
+}
+
+function updateMovement(cs: CharState, bounds: { x: number; y: number; w: number; h: number }) {
+  const dx = cs.tx - cs.x, dy = cs.ty - cs.y;
+  const dist = Math.sqrt(dx * dx + dy * dy);
+  if (dist > 2) {
+    cs.moving = true;
+    cs.x += (dx / dist) * 0.4;
+    cs.y += (dy / dist) * 0.4;
+    cs.wf++;
+    cs.dir = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'right' : 'left') : (dy > 0 ? 'down' : 'up');
+  } else {
+    cs.moving = false; cs.wf = 0; cs.idle--;
+    if (cs.idle <= 0) {
+      const mx = bounds.w * 0.15, my = bounds.h * 0.2;
+      cs.tx = bounds.x + mx + Math.random() * (bounds.w - mx * 2);
+      cs.ty = bounds.y + my + Math.random() * (bounds.h - my * 2);
+      cs.idle = 150 + Math.random() * 300;
+    }
+  }
+}
+
+export { getCS, updateMovement };
