+export function AgentsScene() {
+  const canvasRef = useRef<HTMLCanvasElement>(null);
+  const [agents, setAgents] = useState<AgentInfo[]>(DEFAULT_AGENTS);
+
+  useEffect(() => {
+    const canvas = canvasRef.current;
+    if (!canvas) return;
+    const ctx = canvas.getContext('2d');
+    if (!ctx) return;
+
+    syncCanvasSize(canvas);
+
+    const bounds = { x: 20, y: 20, w: canvas.width - 40, h: canvas.height - 40 };
+
+    // Initialize character states
+    agents.forEach(agent => {
+      getCS(agent.id, bounds.x + bounds.w / 2, bounds.y + bounds.h / 2);
+    });
+
+    let frameCount = 0;
+
+    const tick = () => {
+      clearCanvas(ctx);
+      drawRoom(ctx, bounds);
+
+      agents.forEach(agent => {
+        const cs = getCS(agent.id, bounds.x + bounds.w / 2, bounds.y + bounds.h / 2);
+        updateMovement(cs, bounds);
+
+        // Draw walking character with walk cycle frame and direction
+        const animFrame = Math.floor(cs.wf / 8) % 4; // slower frame rate for walk cycle
+        if (cs.moving) {
+          drawWalkingCharacter(ctx, cs.x, cs.y, agent.tier, animFrame, cs.dir as 'up' | 'down' | 'left' | 'right');
+        } else {
+          // Draw idle frame (frame 0)
+          drawWalkingCharacter(ctx, cs.x, cs.y, agent.tier, 0, cs.dir as 'up' | 'down' | 'left' | 'right');
+        }
+
+        // Draw agent name
+        ctx.fillStyle = '#fff';
+        ctx.font = '10px monospace';
+        ctx.textAlign = 'center';
+        ctx.fillText(agent.name, cs.x + 8, cs.y - 4);
+      });
+
+      frameCount++;
+      requestAnimationFrame(tick);
+    };
+
+    tick();
+
+    return () => {};
+  }, [agents]);
+  
+  return <canvas ref={canvasRef} style={{ width: '100%', height: '100%' }} />;
 }
